window.openAdvanceModal=function(m){const s=m,l=s.getAttribute("data-order-ref"),u=s.getAttribute("data-cust-id"),d=parseFloat(s.getAttribute("data-net"))||0,t=(s.getAttribute("data-division")||"").toLowerCase();document.getElementById("adv_orderRef").value=l,document.getElementById("adv_customerId").value=u,document.getElementById("adv_netAmount").value=d;let e=100;t.includes("dhaka")&&(e=50),document.getElementById("adv_delivery").value=e,document.getElementById("adv_paidAmount").value="",document.getElementById("adv_note").value="";const n=document.getElementById("adv_paymentType");n&&(n.value="Advance");const a=d+e;document.getElementById("adv_dueAmount").textContent=a.toFixed(2);const o=document.getElementById("advanceModal");o.parentElement!==document.body&&document.body.appendChild(o),new bootstrap.Modal(o).show()},document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll(".confirm-toggle").forEach(d=>{d.addEventListener("change",function(){const t=this,e=t.getAttribute("data-id"),n=t.checked,a=document.getElementById(`status-badge-${e}`),o=t.nextElementSibling;o&&(o.textContent=n?"Yes":"No");const r=new URLSearchParams;r.append("id",e),r.append("isConfirmed",n);const i=document.querySelector('input[name="__RequestVerificationToken"]')?.value;fetch("/SalesOrder/ToggleConfirmation",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded",RequestVerificationToken:i},body:r.toString()}).then(c=>c.json()).then(c=>{c.success?a&&(a.textContent=c.newStatus,c.newStatus==="Confirmed"?a.className="badge bg-success text-white":c.newStatus==="Pending"?a.className="badge bg-warning text-dark":a.className="badge bg-secondary-subtle text-dark"):s(t,o,!n,c.message)}).catch(c=>{console.error("Error:",c),s(t,o,!n,"Connection failed.")})})});function s(d,t,e,n){d.checked=e,t&&(t.textContent=e?"Yes":"No"),alert("Action failed: "+n)}const l=document.getElementById("adv_paidAmount");l&&l.addEventListener("input",function(){const d=parseFloat(document.getElementById("adv_netAmount").value)||0,t=parseFloat(document.getElementById("adv_delivery").value)||0,e=d+t,n=parseFloat(this.value)||0,a=e-n;document.getElementById("adv_dueAmount").textContent=a.toFixed(2);const o=document.getElementById("adv_paymentType");o&&(n>=e?o.value="Sale":o.value="Advance")});const u=document.getElementById("advanceForm");u&&u.addEventListener("submit",function(d){d.preventDefault();const t={CustomerId:parseInt(document.getElementById("adv_customerId").value),PaymentMethodId:parseInt(document.getElementById("adv_paymentMethod").value),PaymentType:document.getElementById("adv_paymentType").value,Amount:parseFloat(document.getElementById("adv_paidAmount").value),TransactionReference:document.getElementById("adv_orderRef").value,Notes:document.getElementById("adv_note").value};fetch("/order/add-payment",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(t)}).then(e=>e.json()).then(e=>{e.success?(alert("Payment Added Successfully!"),location.reload()):alert("Error: "+e.message)}).catch(e=>alert("Network Error"))})});
